18	/// Check whether a file appears to contain binary content by examining
19	/// the first chunk for NUL bytes.
20	fn is_binary_file(path: &Path) -> io::Result<bool> {
21	    use std::io::Read;
22	    let mut file = fs::File::open(path)?;
23	    let mut buffer = [0u8; 8192];
24	    let bytes_read = file.read(&mut buffer)?;
25	    Ok(buffer[..bytes_read].contains(&0))
26	}
