28	/// Validate that a resolved path stays within the given workspace root.
29	/// Returns the canonical path on success, or an error if the path escapes
30	/// the workspace boundary (e.g. via `../` traversal or symlink).
31	fn validate_workspace_boundary(resolved: &Path, workspace_root: &Path) -> io::Result<()> {
32	    if !resolved.starts_with(workspace_root) {
33	        return Err(io::Error::new(
34	            io::ErrorKind::PermissionDenied,
35	            format!(
36	                "path {} escapes workspace boundary {}",
37	                resolved.display(),
38	                workspace_root.display()
39	            ),
40	        ));
41	    }
42	    Ok(())
43	}
