173	/// Reads a text file and returns a line-windowed payload.
174	pub fn read_file(
175	    path: &str,
176	    offset: Option<usize>,
177	    limit: Option<usize>,
178	) -> io::Result<ReadFileOutput> {
179	    let absolute_path = normalize_path(path)?;
180	
181	    // Check file size before reading
182	    let metadata = fs::metadata(&absolute_path)?;
183	    if metadata.len() > MAX_READ_SIZE {
184	        return Err(io::Error::new(
185	            io::ErrorKind::InvalidData,
186	            format!(
187	                "file is too large ({} bytes, max {} bytes)",
188	                metadata.len(),
189	                MAX_READ_SIZE
190	            ),
191	        ));
192	    }
193	
194	    // Detect binary files
195	    if is_binary_file(&absolute_path)? {
196	        return Err(io::Error::new(
197	            io::ErrorKind::InvalidData,
198	            "file appears to be binary",
199	        ));
200	    }
201	
202	    let content = fs::read_to_string(&absolute_path)?;
203	    let lines: Vec<&str> = content.lines().collect();
204	    let start_index = offset.unwrap_or(0).min(lines.len());
205	    let end_index = limit.map_or(lines.len(), |limit| {
206	        start_index.saturating_add(limit).min(lines.len())
207	    });
208	    let selected = lines[start_index..end_index].join("\n");
209	
210	    Ok(ReadFileOutput {
211	        kind: String::from("text"),
212	        file: TextFilePayload {
213	            file_path: absolute_path.to_string_lossy().into_owned(),
214	            content: selected,
215	            num_lines: end_index.saturating_sub(start_index),
216	            start_line: start_index.saturating_add(1),
217	            total_lines: lines.len(),
218	        },
219	    })
220	}
