222	/// Replaces a file's contents and returns patch metadata.
223	pub fn write_file(path: &str, content: &str) -> io::Result<WriteFileOutput> {
224	    if content.len() > MAX_WRITE_SIZE {
225	        return Err(io::Error::new(
226	            io::ErrorKind::InvalidData,
227	            format!(
228	                "content is too large ({} bytes, max {} bytes)",
229	                content.len(),
230	                MAX_WRITE_SIZE
231	            ),
232	        ));
233	    }
234	
235	    let absolute_path = normalize_path_allow_missing(path)?;
236	    let original_file = fs::read_to_string(&absolute_path).ok();
237	    if let Some(parent) = absolute_path.parent() {
238	        fs::create_dir_all(parent)?;
239	    }
240	    fs::write(&absolute_path, content)?;
241	
242	    Ok(WriteFileOutput {
243	        kind: if original_file.is_some() {
244	            String::from("update")
245	        } else {
246	            String::from("create")
247	        },
248	        file_path: absolute_path.to_string_lossy().into_owned(),
249	        content: content.to_owned(),
250	        structured_patch: make_patch(original_file.as_deref().unwrap_or(""), content),
251	        original_file,
252	        git_diff: None,
253	    })
254	}
