256	/// Performs an in-file string replacement and returns patch metadata.
257	pub fn edit_file(
258	    path: &str,
259	    old_string: &str,
260	    new_string: &str,
261	    replace_all: bool,
262	) -> io::Result<EditFileOutput> {
263	    let absolute_path = normalize_path(path)?;
264	    let original_file = fs::read_to_string(&absolute_path)?;
265	    if old_string == new_string {
266	        return Err(io::Error::new(
267	            io::ErrorKind::InvalidInput,
268	            "old_string and new_string must differ",
269	        ));
270	    }
271	    if !original_file.contains(old_string) {
272	        return Err(io::Error::new(
273	            io::ErrorKind::NotFound,
274	            "old_string not found in file",
275	        ));
276	    }
277	
278	    let updated = if replace_all {
279	        original_file.replace(old_string, new_string)
280	    } else {
281	        original_file.replacen(old_string, new_string, 1)
282	    };
283	    fs::write(&absolute_path, &updated)?;
284	
285	    Ok(EditFileOutput {
286	        file_path: absolute_path.to_string_lossy().into_owned(),
287	        old_string: old_string.to_owned(),
288	        new_string: new_string.to_owned(),
289	        original_file: original_file.clone(),
290	        structured_patch: make_patch(&original_file, &updated),
291	        user_modified: false,
292	        replace_all,
293	        git_diff: None,
294	    })
295	}
