297	/// Expands a glob pattern and returns matching filenames.
298	pub fn glob_search(pattern: &str, path: Option<&str>) -> io::Result<GlobSearchOutput> {
299	    let started = Instant::now();
300	    let base_dir = path
301	        .map(normalize_path)
302	        .transpose()?
303	        .unwrap_or(std::env::current_dir()?);
304	    let search_pattern = if Path::new(pattern).is_absolute() {
305	        pattern.to_owned()
306	    } else {
307	        base_dir.join(pattern).to_string_lossy().into_owned()
308	    };
309	
310	    let mut matches = Vec::new();
311	    let entries = glob::glob(&search_pattern)
312	        .map_err(|error| io::Error::new(io::ErrorKind::InvalidInput, error.to_string()))?;
313	    for entry in entries.flatten() {
314	        if entry.is_file() {
315	            matches.push(entry);
316	        }
317	    }
318	
319	    matches.sort_by_key(|path| {
320	        fs::metadata(path)
321	            .and_then(|metadata| metadata.modified())
322	            .ok()
323	            .map(Reverse)
324	    });
325	
326	    let truncated = matches.len() > 100;
327	    let filenames = matches
328	        .into_iter()
329	        .take(100)
330	        .map(|path| path.to_string_lossy().into_owned())
331	        .collect::<Vec<_>>();
332	
333	    Ok(GlobSearchOutput {
334	        duration_ms: started.elapsed().as_millis(),
335	        num_files: filenames.len(),
336	        filenames,
337	        truncated,
338	    })
339	}
