341	/// Runs a regex search over workspace files with optional context lines.
342	pub fn grep_search(input: &GrepSearchInput) -> io::Result<GrepSearchOutput> {
343	    let base_path = input
344	        .path
345	        .as_deref()
346	        .map(normalize_path)
347	        .transpose()?
348	        .unwrap_or(std::env::current_dir()?);
349	
350	    let regex = RegexBuilder::new(&input.pattern)
351	        .case_insensitive(input.case_insensitive.unwrap_or(false))
352	        .dot_matches_new_line(input.multiline.unwrap_or(false))
353	        .build()
354	        .map_err(|error| io::Error::new(io::ErrorKind::InvalidInput, error.to_string()))?;
355	
356	    let glob_filter = input
357	        .glob
358	        .as_deref()
359	        .map(Pattern::new)
360	        .transpose()
361	        .map_err(|error| io::Error::new(io::ErrorKind::InvalidInput, error.to_string()))?;
362	    let file_type = input.file_type.as_deref();
363	    let output_mode = input
364	        .output_mode
365	        .clone()
366	        .unwrap_or_else(|| String::from("files_with_matches"));
367	    let context = input.context.or(input.context_short).unwrap_or(0);
368	
369	    let mut filenames = Vec::new();
370	    let mut content_lines = Vec::new();
371	    let mut total_matches = 0usize;
372	
373	    for file_path in collect_search_files(&base_path)? {
374	        if !matches_optional_filters(&file_path, glob_filter.as_ref(), file_type) {
375	            continue;
376	        }
377	
378	        let Ok(file_contents) = fs::read_to_string(&file_path) else {
379	            continue;
380	        };
381	
382	        if output_mode == "count" {
383	            let count = regex.find_iter(&file_contents).count();
384	            if count > 0 {
385	                filenames.push(file_path.to_string_lossy().into_owned());
386	                total_matches += count;
387	            }
388	            continue;
389	        }
390	
391	        let lines: Vec<&str> = file_contents.lines().collect();
392	        let mut matched_lines = Vec::new();
393	        for (index, line) in lines.iter().enumerate() {
394	            if regex.is_match(line) {
395	                total_matches += 1;
396	                matched_lines.push(index);
397	            }
398	        }
399	
400	        if matched_lines.is_empty() {
401	            continue;
402	        }
403	
404	        filenames.push(file_path.to_string_lossy().into_owned());
405	        if output_mode == "content" {
406	            for index in matched_lines {
407	                let start = index.saturating_sub(input.before.unwrap_or(context));
408	                let end = (index + input.after.unwrap_or(context) + 1).min(lines.len());
409	                for (current, line) in lines.iter().enumerate().take(end).skip(start) {
410	                    let prefix = if input.line_numbers.unwrap_or(true) {
411	                        format!("{}:{}:", file_path.to_string_lossy(), current + 1)
412	                    } else {
413	                        format!("{}:", file_path.to_string_lossy())
414	                    };
415	                    content_lines.push(format!("{prefix}{line}"));
416	                }
417	            }
418	        }
419	    }
420	
421	    let (filenames, applied_limit, applied_offset) =
422	        apply_limit(filenames, input.head_limit, input.offset);
423	    let content_output = if output_mode == "content" {
424	        let (lines, limit, offset) = apply_limit(content_lines, input.head_limit, input.offset);
425	        return Ok(GrepSearchOutput {
426	            mode: Some(output_mode),
427	            num_files: filenames.len(),
428	            filenames,
429	            num_lines: Some(lines.len()),
430	            content: Some(lines.join("\n")),
431	            num_matches: None,
432	            applied_limit: limit,
433	            applied_offset: offset,
434	        });
435	    } else {
436	        None
437	    };
438	
439	    Ok(GrepSearchOutput {
440	        mode: Some(output_mode.clone()),
441	        num_files: filenames.len(),
442	        filenames,
443	        content: content_output,
444	        num_lines: None,
445	        num_matches: (output_mode == "count").then_some(total_matches),
446	        applied_limit,
447	        applied_offset,
448	    })
449	}
