451	fn collect_search_files(base_path: &Path) -> io::Result<Vec<PathBuf>> {
452	    if base_path.is_file() {
453	        return Ok(vec![base_path.to_path_buf()]);
454	    }
455	
456	    let mut files = Vec::new();
457	    for entry in WalkDir::new(base_path) {
458	        let entry = entry.map_err(|error| io::Error::other(error.to_string()))?;
459	        if entry.file_type().is_file() {
460	            files.push(entry.path().to_path_buf());
461	        }
462	    }
463	    Ok(files)
464	}
