466	fn matches_optional_filters(
467	    path: &Path,
468	    glob_filter: Option<&Pattern>,
469	    file_type: Option<&str>,
470	) -> bool {
471	    if let Some(glob_filter) = glob_filter {
472	        let path_string = path.to_string_lossy();
473	        if !glob_filter.matches(&path_string) && !glob_filter.matches_path(path) {
474	            return false;
475	        }
476	    }
477	
478	    if let Some(file_type) = file_type {
479	        let extension = path.extension().and_then(|extension| extension.to_str());
480	        if extension != Some(file_type) {
481	            return false;
482	        }
483	    }
484	
485	    true
486	}
