488	fn apply_limit<T>(
489	    items: Vec<T>,
490	    limit: Option<usize>,
491	    offset: Option<usize>,
492	) -> (Vec<T>, Option<usize>, Option<usize>) {
493	    let offset_value = offset.unwrap_or(0);
494	    let mut items = items.into_iter().skip(offset_value).collect::<Vec<_>>();
495	    let explicit_limit = limit.unwrap_or(250);
496	    if explicit_limit == 0 {
497	        return (items, None, (offset_value > 0).then_some(offset_value));
498	    }
499	
500	    let truncated = items.len() > explicit_limit;
501	    items.truncate(explicit_limit);
502	    (
503	        items,
504	        truncated.then_some(explicit_limit),
505	        (offset_value > 0).then_some(offset_value),
506	    )
507	}
