509	fn make_patch(original: &str, updated: &str) -> Vec<StructuredPatchHunk> {
510	    let mut lines = Vec::new();
511	    for line in original.lines() {
512	        lines.push(format!("-{line}"));
513	    }
514	    for line in updated.lines() {
515	        lines.push(format!("+{line}"));
516	    }
517	
518	    vec![StructuredPatchHunk {
519	        old_start: 1,
520	        old_lines: original.lines().count(),
521	        new_start: 1,
522	        new_lines: updated.lines().count(),
523	        lines,
524	    }]
525	}
