527	fn normalize_path(path: &str) -> io::Result<PathBuf> {
528	    let candidate = if Path::new(path).is_absolute() {
529	        PathBuf::from(path)
530	    } else {
531	        std::env::current_dir()?.join(path)
532	    };
533	    candidate.canonicalize()
534	}
535	
536	fn normalize_path_allow_missing(path: &str) -> io::Result<PathBuf> {
537	    let candidate = if Path::new(path).is_absolute() {
538	        PathBuf::from(path)
539	    } else {
540	        std::env::current_dir()?.join(path)
541	    };
542	
543	    if let Ok(canonical) = candidate.canonicalize() {
544	        return Ok(canonical);
545	    }
546	
547	    if let Some(parent) = candidate.parent() {
548	        let canonical_parent = parent
549	            .canonicalize()
550	            .unwrap_or_else(|_| parent.to_path_buf());
551	        if let Some(name) = candidate.file_name() {
552	            return Ok(canonical_parent.join(name));
553	        }
554	    }
555	
556	    Ok(candidate)
557	}
