559	/// Read a file with workspace boundary enforcement.
560	pub fn read_file_in_workspace(
561	    path: &str,
562	    offset: Option<usize>,
563	    limit: Option<usize>,
564	    workspace_root: &Path,
565	) -> io::Result<ReadFileOutput> {
566	    let absolute_path = normalize_path(path)?;
567	    let canonical_root = workspace_root
568	        .canonicalize()
569	        .unwrap_or_else(|_| workspace_root.to_path_buf());
570	    validate_workspace_boundary(&absolute_path, &canonical_root)?;
571	    read_file(path, offset, limit)
572	}
