604	/// Check whether a path is a symlink that resolves outside the workspace.
605	pub fn is_symlink_escape(path: &Path, workspace_root: &Path) -> io::Result<bool> {
606	    let metadata = fs::symlink_metadata(path)?;
607	    if !metadata.is_symlink() {
608	        return Ok(false);
609	    }
610	    let resolved = path.canonicalize()?;
611	    let canonical_root = workspace_root
612	        .canonicalize()
613	        .unwrap_or_else(|_| workspace_root.to_path_buf());
614	    Ok(!resolved.starts_with(&canonical_root))
615	}
