328	                    let role = match msg.role {
329	                        crate::session::MessageRole::System => "system",
330	                        crate::session::MessageRole::User => "user",
331	                        crate::session::MessageRole::Assistant => "assistant",
332	                        crate::session::MessageRole::Tool => "tool",
333	                    };
334	                    let blocks: Vec<String> = msg.blocks.iter().map(|b| match b {
335	                        ContentBlock::Text { text } => {
336	                            let t = if text.len() > 100 { format!("{}...", &text[..100]) } else { text.clone() };
337	                            format!("Text({t})")
338	                        }
339	                        ContentBlock::ToolUse { name, .. } => format!("ToolUse({name})"),
340	                        ContentBlock::ToolResult { tool_name, is_error, .. } => {
341	                            format!("ToolResult({tool_name}{})", if *is_error { " ERROR" } else { "" })
342	                        }
343	                    }).collect();
344	                    eprintln!("  [{i}] {role:<10} {}", blocks.join(" | "));
345	                }
346	                eprintln!("  system_prompt: {} segment(s)", self.system_prompt.len());
347	            }
348	            let request = ApiRequest {
349	                system_prompt: self.system_prompt.clone(),
350	                messages: self.session.messages.clone(),
351	            };
352	            if std::env::var("CLAW_LOG_INPUTS").is_ok() {
353	                self.append_api_input_log(iterations, &request);
354	            }
355	            let events = match self.api_client.stream(request) {
356	                Ok(events) => events,
357	                Err(error) => {
358	                    self.record_turn_failed(iterations, &error);
359	                    return Err(error);
360	                }
361	            };
362	            let (assistant_message, usage, turn_prompt_cache_events) =
363	                match build_assistant_message(events) {
364	                    Ok(result) => result,
365	                    Err(error) => {
366	                        self.record_turn_failed(iterations, &error);
367	                        return Err(error);
368	                    }
369	                };
370	            if let Some(usage) = usage {
371	                self.usage_tracker.record(usage);
372	            }
373	            prompt_cache_events.extend(turn_prompt_cache_events);
374	            let pending_tool_uses = assistant_message
375	                .blocks
376	                .iter()
377	                .filter_map(|block| match block {
378	                    ContentBlock::ToolUse { id, name, input } => {
379	                        Some((id.clone(), name.clone(), input.clone()))
380	                    }
381	                    _ => None,
382	                })
383	                .collect::<Vec<_>>();
384	            self.record_assistant_iteration(
385	                iterations,
386	                &assistant_message,
387	                pending_tool_uses.len(),
388	            );
389	
390	            self.session
391	                .push_message(assistant_message.clone())
392	                .map_err(|error| RuntimeError::new(error.to_string()))?;
393	            assistant_messages.push(assistant_message);
394	
395	            if pending_tool_uses.is_empty() {
396	                break;
397	            }
398	
