420	                            &format!("PreToolUse hook failed for tool `{tool_name}`"),
421	                        ),
422	                    }
423	                } else if pre_hook_result.is_denied() {
424	                    PermissionOutcome::Deny {
425	                        reason: format_hook_message(
426	                            &pre_hook_result,
427	                            &format!("PreToolUse hook denied tool `{tool_name}`"),
428	                        ),
429	                    }
430	                } else if let Some(prompt) = prompter.as_mut() {
