437	                } else {
438	                    self.permission_policy.authorize_with_context(
439	                        &tool_name,
440	                        &effective_input,
441	                        &permission_context,
442	                        None,
443	                    )
444	                };
445	
446	                let result_message = match permission_outcome {
447	                    PermissionOutcome::Allow => {
448	                        self.record_tool_started(iterations, &tool_name);
449	                        let (mut output, mut is_error) =
450	                            match self.tool_executor.execute(&tool_name, &effective_input) {
451	                                Ok(output) => (output, false),
452	                                Err(error) => (error.to_string(), true),
453	                            };
454	                        output = merge_hook_feedback(pre_hook_result.messages(), output, false);
455	
456	                        let post_hook_result = if is_error {
457	                            self.run_post_tool_use_failure_hook(
458	                                &tool_name,
459	                                &effective_input,
460	                                &output,
461	                            )
462	                        } else {
463	                            self.run_post_tool_use_hook(
464	                                &tool_name,
465	                                &effective_input,
466	                                &output,
467	                                false,
468	                            )
469	                        };
470	                        if post_hook_result.is_denied()
471	                            || post_hook_result.is_failed()
472	                            || post_hook_result.is_cancelled()
473	                        {
474	                            is_error = true;
475	                        }
476	                        output = merge_hook_feedback(
477	                            post_hook_result.messages(),
478	                            output,
479	                            post_hook_result.is_denied()
480	                                || post_hook_result.is_failed()
481	                                || post_hook_result.is_cancelled(),
482	                        );
483	
484	                        ConversationMessage::tool_result(tool_use_id, tool_name, output, is_error)
485	                    }
486	                    PermissionOutcome::Deny { reason } => ConversationMessage::tool_result(
487	                        tool_use_id,
488	                        tool_name,
489	                        merge_hook_feedback(pre_hook_result.messages(), reason, true),
490	                        true,
491	                    ),
492	                };
493	                self.session
494	                    .push_message(result_message.clone())
495	                    .map_err(|error| RuntimeError::new(error.to_string()))?;
496	                self.record_tool_finished(iterations, &result_message);
497	                tool_results.push(result_message);
498	            }
499	        }
500	
501	        let auto_compaction = self.maybe_auto_compact();
502	
503	        let summary = TurnSummary {
504	            assistant_messages,
505	            tool_results,
506	            prompt_cache_events,
507	            iterations,
508	            usage: self.usage_tracker.cumulative_usage(),
509	            auto_compaction,
510	        };
511	        self.record_turn_completed(&summary);
512	
513	        Ok(summary)
514	    }
